#include <bits/stdc++.h>
using namespace std;
int main(){
	string s1,s2;
	getline(cin,s1);
	s2=s1;
	for(int i=0;i<s1.length();i++){
		if(s1[i]>64&&91>s1[i]||s1[i]>96&&123>s1[i]){
			if(s1[i]=='A')
				{s2[i]='[';}
			if(s1[i]=='a')
				{s2[i]='{';}
				s2[i]=s2[i]-1;	
				}
		}
	cout<<s2;
}
